// callback echo.HandlerFunc returned by {Op}CallbackHandler at
// whatever URL path they advertise to senders.
type CallbackReceiverInterface interface {

	// HandleOnResourceGetCallback handles the GET callback for resourceEvent.
	HandleOnResourceGetCallback(ctx echo.Context, params OnResourceGetParams) error

	// HandleOnResourcePostCallback handles the POST callback for resourceEvent.
	HandleOnResourcePostCallback(ctx echo.Context, params OnResourcePostParams) error
}

// OnResourceGetCallbackHandler returns the echo.HandlerFunc for the resourceEvent callback.
// Mount this at the URL path advertised to callback senders. Errors
// during parameter binding are returned via echo.NewHTTPError so echo's
// error-handling chain reports them as 400. Middlewares are applied in
// the order provided -- the last argument becomes the outermost wrapper.
func OnResourceGetCallbackHandler(si CallbackReceiverInterface, middlewares ...echo.MiddlewareFunc) echo.HandlerFunc {
	h := echo.HandlerFunc(func(ctx echo.Context) error {
		var err error
		_ = err

		// Parameter object where we will unmarshal all parameters from the context.
		var params OnResourceGetParams

		// ------------- Required query parameter "cbid" -------------

		err = runtime.BindQueryParameterWithOptions("form", true, true, "cbid", ctx.QueryParams(), &params.Cbid, runtime.BindQueryParameterOptions{Type: "", Format: ""})
		if err != nil {
			return echo.NewHTTPError(http.StatusBadRequest, fmt.Sprintf("Invalid format for parameter cbid: %s", err))
		}

		return si.HandleOnResourceGetCallback(ctx, params)
	})
	for _, mw := range middlewares {
		h = mw(h)
	}
	return h
}

